sql:
SELECT DISTINCT g.type_id, g.size_id
FROM garments g
JOIN size_measurements sm ON g.size_id = sm.size_id;

external_knowledge:
External knowledge to enhance clarity:
- 'available garments' refers to garments that are not discontinued;
- 'categories' refer to the categories 'Mens', 'Womens', or 'Kids'.

sql:
SELECT isize.country, MAX(isize.standard_description) as highest_description
FROM international_sizes isize
GROUP BY isize.country;

SELECT international_sizes.int_size_name, size_measurements.measurement_value
FROM international_sizes
JOIN size_measurements ON international_sizes.size_id = size_measurements.size_id;

SELECT gtm.type_id, gtm.point_id, AVG(gtm.measurement_value) AS average_measurement
FROM garment_type_measurements gtm
GROUP BY gtm.type_id, gtm.point_id;

SELECT type_id, point_id, measurement_unit, ROUND(AVG(measurement_value)) AS avg_measurement_value
FROM garment_type_measurements
GROUP BY type_id, point_id, measurement_unit;
